#!/usr/bin/env bash
set -euo pipefail

WORKSPACE="/root/.openclaw/workspace"
SKILL_DIR="$WORKSPACE/skills/notion-workspace"
CREDENTIALS_DIR="${HOME}/.openclaw/credentials"
ENV_FILE="$CREDENTIALS_DIR/notion-workspace.env"

write_embedded_file() {
  local dest="$1"
  local b64="$2"
  mkdir -p "$(dirname "$dest")"
  printf %s "$b64" | base64 -d > "$dest"
}

mkdir -p "$SKILL_DIR"
mkdir -p "$CREDENTIALS_DIR"

echo "Installing Notion Workspace skill into:"
echo "  $SKILL_DIR"
echo ""
write_embedded_file "$SKILL_DIR/SKILL.md" ""
write_embedded_file "$SKILL_DIR/README.md" ""
write_embedded_file "$SKILL_DIR/install.sh" ""
write_embedded_file "$SKILL_DIR/scripts/notion_api.py" ""

chmod +x "$SKILL_DIR/scripts/notion_api.py" || true
chmod +x "$SKILL_DIR/install.sh" || true

echo "Skill files installed."
echo ""

if [[ -f "$ENV_FILE" ]]; then
  echo "Existing Notion credentials found at:"
  echo "  $ENV_FILE"
  read -r -p "Replace them now? [y/N] " overwrite
  case "$overwrite" in
    y|Y|yes|YES)
      ;;
    *)
      echo "Keeping existing credentials."
      echo "Running verification..."
      python3 "$SKILL_DIR/scripts/notion_api.py" me
      echo ""
      echo "Notion is ready."
      echo "Skill location: $SKILL_DIR"
      echo "Credentials location: $ENV_FILE"
      if [[ -f "$SKILL_DIR/page_ids.txt" ]]; then
        echo "Page IDs location: $SKILL_DIR/page_ids.txt"
      fi
      echo ""
      echo "--------------------------------------------------"
      echo "Installation complete."
      echo ""
      echo "Now tell your OpenClaw agent about this setup with the prompt below:"
      echo "--------------------------------------------------"
      cat <<PROMPT
Notion is configured in this workspace.

Use the Notion skill at:
$SKILL_DIR

Credentials are stored at:
$ENV_FILE

When I ask you to read from or write to Notion, use this skill and its helper script.

Main helper script:
$SKILL_DIR/scripts/notion_api.py
PROMPT
      exit 0
      ;;
  esac
fi

read -r -p "Paste your Notion secret key: " notion_key

if [[ -z "$notion_key" ]]; then
  echo "No key entered. Aborting."
  exit 1
fi


cat > "$ENV_FILE" <<EOF
NOTION_API_KEY=$notion_key
EOF
chmod 600 "$ENV_FILE"

rm -f "$SKILL_DIR/page_ids.txt"

echo ""
echo "Saved credentials to $ENV_FILE"
echo "Verifying access..."
python3 "$SKILL_DIR/scripts/notion_api.py" me

echo ""
echo "Notion Workspace skill installed successfully."
echo "Skill location: $SKILL_DIR"
echo "Credentials location: $ENV_FILE"
echo ""
echo "--------------------------------------------------"
echo "Installation complete."
echo ""
echo "Now tell your OpenClaw agent about this setup with the prompt below:"
echo "--------------------------------------------------"
cat <<PROMPT
Notion is configured in this workspace.

Use the Notion skill at:
$SKILL_DIR

Credentials are stored at:
$ENV_FILE

When I ask you to read from or write to Notion, use this skill and its helper script.

Main helper script:
$SKILL_DIR/scripts/notion_api.py
PROMPT
